import { useState, useEffect, useCallback } from "react";
import { ethers } from "ethers";

function PayslipViewer({ payslipNFT, address, notify }) {
  const [payslips, setPayslips]       = useState([]);
  const [loading, setLoading]         = useState(false);
  const [totalSupply, setTotalSupply] = useState("0");

  const loadPayslips = useCallback(async () => {
    if (!payslipNFT || !address) return;
    setLoading(true);
    try {
      const tokenIds = await payslipNFT.getWorkerPayslips(address);
      const supply   = await payslipNFT.totalSupply();
      setTotalSupply(supply.toString());
      const data = await Promise.all(
        tokenIds.map(async (id) => {
          const p = await payslipNFT.getPayslip(id);
          return {
            tokenId:     id.toString(),
            employer:    p.employer,
            worker:      p.worker,
            amount:      ethers.utils.formatUnits(p.amount, 6),
            timestamp:   new Date(p.timestamp.toNumber() * 1000).toLocaleString(),
            companyName: p.companyName,
          };
        })
      );
      setPayslips(data.reverse());
    } catch (e) {
      console.error(e);
    }
    setLoading(false);
  }, [payslipNFT, address]);

  useEffect(() => { loadPayslips(); }, [loadPayslips]);

  const totalEarned = payslips.reduce((sum, p) => sum + parseFloat(p.amount), 0).toFixed(2);

  const openExplorer = () => {
    window.open("https://testnet.arcscan.app", "_blank");
  };

  return (
    <div>
      <div style={styles.headerCard}>
        <div>
          <h2 style={styles.title}>My Payslip NFTs</h2>
          <p style={styles.sub}>Soulbound proof of income — permanently stored onchain</p>
        </div>
        <div style={styles.statsRow}>
          <div style={styles.stat}>
            <div style={styles.statNum}>{payslips.length}</div>
            <div style={styles.statLabel}>My Payslips</div>
          </div>
          <div style={styles.stat}>
            <div style={styles.statNum}>{totalSupply}</div>
            <div style={styles.statLabel}>Total Minted</div>
          </div>
          <div style={styles.stat}>
            <div style={styles.statNum}>{totalEarned}</div>
            <div style={styles.statLabel}>Total Earned USDC</div>
          </div>
        </div>
      </div>

      {loading && <div style={styles.loading}>Loading your payslips...</div>}

      {!loading && payslips.length === 0 && (
        <div style={styles.emptyState}>
          <div style={styles.emptyIcon}>🎫</div>
          <p style={styles.emptyText}>No payslips yet</p>
          <p style={styles.emptySub}>Claim your salary to mint your first payslip NFT</p>
        </div>
      )}

      <div style={styles.grid}>
        {payslips.map((p) => (
          <div key={p.tokenId} style={styles.payslipCard}>
            <div style={styles.cardHeader}>
              <div style={styles.nftBadge}>NFT #{p.tokenId}</div>
              <div style={styles.soulbound}>🔒 Soulbound</div>
            </div>
            <div style={styles.companyName}>{p.companyName || "Unknown Company"}</div>
            <div style={styles.amountRow}>
              <div style={styles.amountLabel}>Amount Paid</div>
              <div style={styles.amount}>
                {parseFloat(p.amount).toFixed(4)}
                <span style={styles.usdc}> USDC</span>
              </div>
            </div>
            <div style={styles.details}>
              <div style={styles.detailRow}>
                <span style={styles.detailLabel}>📅 Date</span>
                <span style={styles.detailValue}>{p.timestamp}</span>
              </div>
              <div style={styles.detailRow}>
                <span style={styles.detailLabel}>🏢 Employer</span>
                <span style={styles.detailValue}>{p.employer.slice(0, 8)}...{p.employer.slice(-6)}</span>
              </div>
              <div style={styles.detailRow}>
                <span style={styles.detailLabel}>👷 Worker</span>
                <span style={styles.detailValue}>{p.worker.slice(0, 8)}...{p.worker.slice(-6)}</span>
              </div>
            </div>
            <div style={styles.cardFooter}>
              <span style={styles.verified}>✅ Verified Onchain</span>
              <button onClick={openExplorer} style={styles.explorerBtn}>
                View on Explorer
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

const styles = {
  headerCard:  { background: "#1a1a2e", borderRadius: "16px", padding: "30px", marginBottom: "24px", display: "flex", justifyContent: "space-between", alignItems: "center" },
  title:       { fontSize: "22px", fontWeight: "700", color: "#fff", marginBottom: "8px" },
  sub:         { color: "#888", fontSize: "14px" },
  statsRow:    { display: "flex", gap: "24px" },
  stat:        { textAlign: "center" },
  statNum:     { fontSize: "24px", fontWeight: "800", color: "#5865f2" },
  statLabel:   { fontSize: "11px", color: "#888", marginTop: "4px" },
  loading:     { textAlign: "center", color: "#888", padding: "40px" },
  emptyState:  { textAlign: "center", padding: "60px 20px" },
  emptyIcon:   { fontSize: "48px", marginBottom: "16px" },
  emptyText:   { color: "#fff", fontSize: "18px", fontWeight: "600" },
  emptySub:    { color: "#888", fontSize: "14px", marginTop: "8px" },
  grid:        { display: "grid", gridTemplateColumns: "1fr 1fr", gap: "20px" },
  payslipCard: { background: "#1a1a2e", borderRadius: "16px", padding: "24px", border: "1px solid #2a2a3e" },
  cardHeader:  { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "16px" },
  nftBadge:    { background: "#5865f2", color: "#fff", padding: "4px 12px", borderRadius: "20px", fontSize: "12px", fontWeight: "600" },
  soulbound:   { fontSize: "12px", color: "#888" },
  companyName: { fontSize: "20px", fontWeight: "700", color: "#fff", marginBottom: "16px" },
  amountRow:   { background: "#0a0a0f", borderRadius: "8px", padding: "16px", marginBottom: "16px" },
  amountLabel: { fontSize: "12px", color: "#888", marginBottom: "4px" },
  amount:      { fontSize: "24px", fontWeight: "800", color: "#00c48c" },
  usdc:        { fontSize: "14px", color: "#888", fontWeight: "400" },
  details:     { marginBottom: "16px" },
  detailRow:   { display: "flex", justifyContent: "space-between", padding: "8px 0", borderBottom: "1px solid #2a2a3e" },
  detailLabel: { fontSize: "13px", color: "#888" },
  detailValue: { fontSize: "13px", color: "#fff", fontWeight: "500" },
  cardFooter:  { display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: "16px" },
  verified:    { fontSize: "12px", color: "#00c48c" },
  explorerBtn: { fontSize: "12px", color: "#5865f2", background: "none", border: "none", cursor: "pointer", padding: 0 },
};

export default PayslipViewer;
